import "std"

func solve(grid: Array<Array<Int64>>, k: Int64): Int64 {
    m := grid.size()
    n := grid[0].size()
    max_k := k + 1
    directions := [[0, 1], [1, 0]]

    // dp[i][j][l] represents the minimal cost to reach (i,j) with l teleports used
    dp := Array<Array<Array<Int64>>>.new(m, Array<Array<Int64>>.new(n, Array<Int64>.new(max_k, std::INT64_MAX)))
    dp[0][0][0] = 0

    queue = Array<Array<Int64>>.new()
    queue.push([0, 0, 0])

    while queue.size() > 0 {
        current := queue.pop(0)
        i := current[0]
        j := current[1]
        l := current[2]

        // Try normal moves
        for dir in directions {
            ni := i + dir[0]
            nj := j + dir[1]
            if ni < m && nj < n {
                new_cost := dp[i][j][l] + grid[ni][nj]
                if new_cost < dp[ni][nj][l] {
                    dp[ni][nj][l] = new_cost
                    queue.push([ni, nj, l])
                }
            }
        }

        // Try teleport if we have remaining teleports
        if l < k {
            for x in 0..m {
                for y in 0..n {
                    if grid[x][y] <= grid[i][j] && (x != i || y != j) {
                        new_l := l + 1
                        if dp[i][j][l] < dp[x][y][new_l] {
                            dp[x][y][new_l] = dp[i][j][l]
                            queue.push([x, y, new_l])
                        }
                    }
                }
            }
        }
    }

    min_cost := std::INT64_MAX
    for l in 0..max_k {
        if dp[m-1][n-1][l] < min_cost {
            min_cost = dp[m-1][n-1][l]
        }
    }

    return min_cost
