import "std/collections"
import "std/array"

func solve(grid: Array<Array<Int64>>, k: Int64): Int64 {
    let m = grid.size()
    let n = grid[0].size()
    let max_k = k
    let dirs = [[0, 1], [1, 0]]

    let dist = Array.fill(m, () => Array.fill(n, () => Array.fill(max_k + 1, () => Int64.max)))
    let heap = collections.PriorityQueue<Array<Int64>>(compare: (a, b) => a[3] < b[3])

    dist[0][0][0] = 0
    heap.push([0, 0, 0, 0])

    while heap.size() > 0 {
        let curr = heap.pop()
        let i = curr[0]
        let j = curr[1]
        let used = curr[2]
        let cost = curr[3]

        if i == m - 1 && j == n - 1 {
            return cost
        }

        if cost > dist[i][j][used] {
            continue
        }

        for dir in dirs {
            let ni = i + dir[0]
            let nj = j + dir[1]
            if ni >= 0 && ni < m && nj >= 0 && nj < n {
                let new_cost = cost + grid[ni][nj]
                if new_cost < dist[ni][nj][used] {
                    dist[ni][nj][used] = new_cost
                    heap.push([ni, nj, used, new_cost])
                }
            }
        }

        if used < max_k {
            for x in 0..m {
                for y in 0..n {
                    if (x != i || y != j) && grid[x][y] <= grid[i][j] {
                        if cost < dist[x][y][used + 1] {
                            dist[x][y][used + 1] = cost
                            heap.push([x, y, used + 1, cost])
                        }
                    }
                }
            }
        }
    }

    return -1
}
