                for y := 0; y < n; y++ {
                    if grid[x][y] <= grid[i][j] and (x != i or y != j) {
                        if cost < dist[x][y][used_k + 1] {
                            dist[x][y][used_k + 1] = cost
                            heap.push([cost, x, y, used_k + 1])
                        }
                    }
