}

func new_priority_queue(): Array {
    return []
}

func (heap: Array) push(item: Array) {
    heap.append(item)
    i := len(heap) - 1
    while i > 0 {
        parent := (i - 1) // 2
        if heap[i][0] < heap[parent][0] {
            heap[i], heap[parent] = heap[parent], heap[i]
            i = parent
        } else {
            break
        }
    }
}

func (heap: Array) pop(): Array {
    if len(heap) == 0 {
        return []
    }
    if len(heap) == 1 {
        return heap.pop()
    }
    result := heap[0]
    heap[0] = heap.pop()
    i := 0
    while true {
        left := 2 * i + 1
        right := 2 * i + 2
        smallest := i
        if left < len(heap) and heap[left][0] < heap[smallest][0] {
            smallest = left
        }
        if right < len(heap) and heap[right][0] < heap[smallest][0] {
            smallest = right
        }
        if smallest != i {
            heap[i], heap[smallest] = heap[smallest], heap[i]
            i = smallest
        } else {
            break
        }
    }
    return result
}

func (heap: Array) is_empty(): Bool {
    return len(heap) == 0
}

func new_array(size: Int64, default_value): Array {
    arr := []
    for i := 0; i < size; i++ {
        arr.append(default_value)
    }
    return arr
}
